($$Saturday Craft session at Hale End Library$$, $$Castle Ave, London E4 9QD$$, $$E4 9QD$$, 51.6093372, 0.0011061, $$Arts & crafts$$, $$11:00$$, $$12:00$$, $$https://maps.google.com/?cid=2210346963052899551&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, $$https://www.walthamforest.gov.uk/events/saturday-craft-session-hale-end-library$$, null, null, 45, $$Parents, babies and young children$$, $$Waltham Forest$$, array[$$Saturday$$], null, $$Council dates listed through 2026-08-15. Check the council event page for changes.$$, $$Arts and crafts every Saturday at Hale End Library. New themes each week and plenty more. Suitable for children aged two and over, but little ones are welcome to be creative with support from their adults. Free event Age group: 5 to 10 year old Please always check our Eventbrite page as from time to time the session will not take place due to other promotional activities taking place at the same time and we will therefore cancel our regular craft session. For more information, you can message us on our Libraries Facebook or Libraries Instagram page. Or send us an email to Libraries.support@walthamforest.gov.uk$$, $$Free$$, false, $$Waltham Forest Best Start in Life events$$, $$https://www.walthamforest.gov.uk/events/saturday-craft-session-hale-end-library$$, $$https://www.walthamforest.gov.uk/sites/default/files/styles/3_2_lossless_responsive/public/2023-09/Kids%20crafts%20%28Carina%29.png.webp?itok=2rLoGM74$$, $$https://www.walthamforest.gov.uk/events/saturday-craft-session-hale-end-library$$, $$ChIJhRQeDqig2EcR36whG9q6rB4$$, $$https://maps.google.com/?cid=2210346963052899551&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, null, 4.3, 45, $$library$$, null, null, null, array[$$2026-07-18$$, $$2026-07-25$$, $$2026-08-01$$, $$2026-08-08$$, $$2026-08-15$$]::date[], null, null, array[$$Saturday$$], $$specific_dates$$, $$Council dates listed through 2026-08-15. Check the council event page for changes.$$, $$published$$),
($$SEND Lego club at Best Start Family Hub: Queens Road$$, $$215 Queens Rd, London E17 8PJ$$, $$E17 8PJ$$, 51.576522, -0.027894799999999997, $$Arts & crafts$$, $$10:30$$, $$12:30$$, $$https://maps.google.com/?cid=2976073963514090931&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, $$https://www.walthamforest.gov.uk/events/send-lego-club-best-start-family-hub-queens-road$$, null, null, 6, $$Parents, babies and young children$$, $$Waltham Forest$$, array[$$Saturday$$], null, $$Council event on 2026-08-01. Check the council event page for changes.$$, $$This is a free session for SEND Families to have the opportunity to join a friendly Lego Club for children. No need to book, just pop along! This session takes place on the first Saturday of each month. Age: 3 years and above Refreshments provided. When you see Curious Carina you can expect play and learning sessions that will support your child’s learning and development.$$, $$Free$$, true, $$Waltham Forest Best Start in Life events$$, $$https://www.walthamforest.gov.uk/events/send-lego-club-best-start-family-hub-queens-road$$, $$https://www.walthamforest.gov.uk/sites/default/files/styles/3_2_lossless_responsive/public/2023-09/Lego%20Club%20-%20lea%20Bridge%20Library%20%28Carina%29.jpg.png.webp?itok=pAbgIqnl$$, $$https://www.walthamforest.gov.uk/events/send-lego-club-best-start-family-hub-queens-road$$, $$ChIJ8QjxFb8ddkgRs9WLfIAjTSk$$, $$https://maps.google.com/?cid=2976073963514090931&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, null, 3.7, 6, $$health$$, null, null, $$2026-08-01$$, array[$$2026-08-01$$]::date[], null, null, array[$$Saturday$$], $$one_off$$, $$Council event on 2026-08-01. Check the council event page for changes.$$, $$published$$),
($$Sensory Play and Learn at Best Start Family Hub: Chingford$$, $$5 Oaks Grove, London E4 6EY$$, $$E4 6EY$$, 51.625715199999995, 0.0096747, $$Baby sensory$$, $$10:00$$, $$11:30$$, $$https://maps.google.com/?cid=9118098950548432754&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, $$https://www.walthamforest.gov.uk/events/sensory-play-and-learn-best-start-family-hub-chingford$$, null, null, 16, $$Parents, babies and young children$$, $$Waltham Forest$$, array[$$Tuesday$$], null, $$Council dates listed through 2026-08-18; term time only. Check the council event page for changes.$$, $$Drop-in session, booking not necessary. Fun, stimulating and interactive sessions for under-fives, inclusive and open to all children, including those with SEND or developmental delay. Children of all abilities play side by side, helping build understanding and friendships from the earliest years. These sessions also allow parents or carers to meet new friends and share knowledge and experiences. All our sessions are inclusive and provide a range of activities that are appropriate for children of all abilities. This is a Best Start in Life weekly session (term time only). When you see Helpful Hakim you can expect an activity to support children with learning and developmental delay or SEND.$$, $$Check council event page$$, true, $$Waltham Forest Best Start in Life events$$, $$https://www.walthamforest.gov.uk/events/sensory-play-and-learn-best-start-family-hub-chingford$$, $$https://www.walthamforest.gov.uk/sites/default/files/styles/3_2_lossless_responsive/public/2023-09/Somewhere%20to%20Belong%20%28Hakim%29.png.webp?itok=HXAvBJwg$$, $$https://www.walthamforest.gov.uk/events/sensory-play-and-learn-best-start-family-hub-chingford$$, $$ChIJq6reh5mg2EcRcidNjq_-iX4$$, $$https://maps.google.com/?cid=9118098950548432754&g_mp=Cidnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLlNlYXJjaFRleHQQAhgEIAA$$, null, 4.4, 16, $$health$$, null, null, null, array[$$2026-07-14$$, $$2026-07-21$$,